module shift_register(D, clk, reset, load, shift, Q);
    input [7:0] D;
    input clk, reset, load, shift;
    output reg [7:0] Q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
        if (reset)
            Q <= 8'b0;
        else if (load)
            Q <= D;
        else if (shift)
            Q <= {Q[6:0], 1'b0};
    end
endmodule
